sql:
SELECT COUNT(*) as num_inactive_feeds 
FROM data_feeds 
WHERE feed_status = 'inactive';

SELECT s.stock_name || ' - ' || r.content AS combined_info
FROM stocks s
JOIN reports r ON s.stock_symbol = r.stock_symbol;

SELECT GROUP_CONCAT(stock_symbol, ', ') AS combined_stock_symbols
FROM (
    SELECT stock_symbol FROM alerts
    INTERSECT
    SELECT stock_symbol FROM predictions
);

SELECT news_date, headline, content
FROM news
WHERE stock_symbol = 'AAPL';

SELECT users.user_name, reports.stock_symbol, reports.report_date
FROM users
INNER JOIN reports ON users.user_id = reports.user_id;

SELECT stock_symbol, close_avg AS average_close_price
FROM stock_data
WHERE date = 'YYYY-MM-DD';

SELECT COUNT(DISTINCT user_id)
FROM alerts
WHERE status = 'active';

SELECT market_cap
FROM stock_data
WHERE stock_symbol = '0' AND date = '1';

SELECT market_name, contact_email
FROM markets
WHERE market_id > 5;

SELECT AVG(high_avg) AS average_high_price
FROM stock_data
WHERE date = '2023-05-01' AND stock_symbol = 'AAPL';

SELECT stock_symbol, close_avg
FROM stock_data
WHERE close_avg > (SELECT AVG(close_avg) FROM stock_data);

SELECT AVG(close_avg) AS avg_close_price
FROM stock_data
WHERE stock_symbol = 'AAPL' AND date = '2023-05-01';

SELECT stock_name, sector
FROM stocks
ORDER BY stock_symbol;

SELECT prediction_id 
FROM predictions 
WHERE predicted_value = (SELECT MAX(predicted_value) FROM predictions);

SELECT stock_symbol, AVG(close_avg) AS average_closing_price
FROM stock_data
GROUP BY stock_symbol;

SELECT open_avg, close_avg, volume_avg, trading_volume, market_cap
FROM stock_data
WHERE stock_symbol = (SELECT stock_symbol FROM predictions WHERE prediction_id = 0);

external_knowledge:
- 'Keeping an eye on' means the user is interested in the stock alerts they have set up;
- 'Recent headlines' refers to news published about those stocks;
- 'Predicted stock values' are forecasts for those stocks.

